      audio.currentTime = Math.max(0, Math.min(time, maxTime));
      setCurrentTime(audio.currentTime);
    }
  }, []);

  return {
    playing,
    loading,
    error,
    currentTime,
    duration,
    playbackRate,
    setPlaybackRate,
    play,
    playSegments,
    playSegmentsWithGaps,
    pause,
    resume,
    stop,
    seek,
  };
}

